<?php require 'config.php'; $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $name=trim($_POST['name']??''); $email=strtolower(trim($_POST['email']??'')); $pass=$_POST['password']??''; if($name&&filter_var($email,FILTER_VALIDATE_EMAIL)&&strlen($pass)>=8){ try{$st=$pdo->prepare('INSERT INTO users(name,email,password_hash) VALUES(?,?,?)');$st->execute([$name,$email,password_hash($pass,PASSWORD_DEFAULT)]); redirect('/login.php?created=1');}catch(Throwable $e){$msg='Email already exists or database error.';} } else {$msg='Please enter valid details. Password must be at least 8 characters.';} } ?>
<!doctype html><html><head><title>Signup</title><link rel="stylesheet" href="/style.css"></head><body><div class="top"><div class="brand">Karacraft Hosting</div><div class="nav"><a href="/login.php">Login</a></div></div><div class="card form"><h1>Create account</h1><?php if($msg):?><div class="alert"><?=h($msg)?></div><?php endif;?><form method="post"><?=csrf_field()?><label>Name</label><input name="name" required><label>Email</label><input name="email" type="email" required><label>Password</label><input name="password" type="password" minlength="8" required><button class="btn">Create Account</button></form></div></body></html>
